#include<bits/stdc++.h>
using namespace std;
const int MAXN=4e5+5;
int a[MAXN];
vector<int>v1[MAXN];
int ans[MAXN];
int vis[MAXN];
int fa[MAXN];
int find(int x){
	if(fa[x]==x)
		return x;
	return fa[x]=find(fa[x]);
}
int main(){
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		int u,v;
		cin>>u>>v;
		v1[u].push_back(v);
		v1[v].push_back(u);
	}

	for(int i=0;i<n;i++){
		fa[i]=i;
	}
	int k;
	cin>>k;
	for(int i=1;i<=k;i++){
		cin>>a[i];
		vis[a[i]]=1;
	}
	for(int i=0;i<n;i++){
		if(!vis[i]){
		//	cout<<i<<endl;
			for(auto v:v1[i]){
			//	cout<<vis[v]<<" "<<v<<endl;
				if(!vis[v]){

					int fx=find(i),fy=find(v);
					if(fx==fy){
						continue;
					}else{
						fa[fx]=fy;
					}
				}
			}
		}
	}
	int cnt=0;
	for(int i=0;i<n;i++){
		if(fa[i]==i&&!vis[i]){
			cnt++;
		}
	}
//	cout<<cnt<<endl;
	int tot=1;
	ans[tot++]=cnt;
	for(int i=k;i>=1;i--){
		int u = a[i];
		cnt++;		
		for(auto v:v1[u]){					
			if(!vis[v]){
				int fx=find(u),fy=find(v);
//				cout << i <<" "<<v<<" "<<k<<"\n";
				if(fx==fy){
					continue;
				}else{
					cnt--;
					fa[fx]=fy;
				}
			}
		}
		ans[tot++]=cnt;
		vis[u]=0;
	}
	for(int i=k+1;i>=1;i--){
		cout<<ans[i]<<endl;
	}
}
